def _call_user_or_builtin(self, f, *args):
    """Call either a UserFunction or a Python callable."""
    if isinstance(f, UserFunction):
        call_env = Environment(parent=f.closure_env)
        for param, arg in zip(f.params, args):
            call_env.set(param, arg)
        try:
            self._eval_body(f.body, call_env)
            return None
        except ReturnSignal as ret:
            return ret.value
    return f(*args)

def _setup_builtins(self):
    self.global_env.set("print", lambda *args: print(*args))
